#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
stack<int> stk;
bool instk[100010];
int dfn[100010],low[100010],dfncnt,scccnt,scc[100010],siz[100010];
void tarjan(int x)
{
    stk.push(x);
    dfn[x]=low[x]=++dfncnt;
    instk[x]=1;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=stk.top();
            stk.pop();
            instk[top]=0;
            siz[scccnt]++;
            scc[top]=scccnt;
        }while(top!=x);
    }
}
int in[100010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                in[scc[j]]++;
            }
        }
    }
    int ans=0;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            ans++;
        }
    }
    printf("%d",ans);
    return 0;
}
